{
  "mode": "method",
  "tests": [
    {
      "name": "valid_progress_calculation",
      "input": {
        "challengeId": "12345"
      },
      "output": 50,
      "notes": "Validates progress calculation with 2 reviewers and 4 submissions, where 2 reviews are submitted."
    },
    {
      "name": "no_reviews_submitted",
      "input": {
        "challengeId": "67890"
      },
      "output": 0,
      "notes": "Tests scenario where no reviews have been submitted for the challenge."
    },
    {
      "name": "no_reviewers",
      "input": {
        "challengeId": "54321"
      },
      "output": 0,
      "notes": "Tests scenario where there are no reviewers for the challenge."
    },
    {
      "name": "all_reviews_submitted",
      "input": {
        "challengeId": "98765"
      },
      "output": 100,
      "notes": "Validates calculation when all reviews are submitted for the available submissions."
    },
    {
      "name": "single_reviewer_multiple_submissions",
      "input": {
        "challengeId": "11111"
      },
      "output": 100,
      "notes": "Tests case with one reviewer and multiple submissions, all reviewed."
    },
    {
      "name": "multiple_reviewers_no_submissions",
      "input": {
        "challengeId": "22222"
      },
      "output": 0,
      "notes": "Tests case with multiple reviewers but no submissions."
    },
    {
      "name": "edge_case_large_numbers",
      "input": {
        "challengeId": "33333"
      },
      "output": 33.33,
      "notes": "Tests calculation with large numbers of reviewers and submissions."
    },
    {
      "name": "invalid_challenge_id",
      "input": {
        "challengeId": "invalid_id"
      },
      "output": "error",
      "notes": "Tests handling of an invalid challenge ID."
    }
  ],
  "assumptions": "The Resource API and Review API are operational and return expected data.",
  "notes": "Ensure the endpoint is accessible to all user roles."
}
